var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 맛있게 드세요!","JPN":"さあ、食べましょう！","ENG":"Enjoy!","TWN":"來，請慢用！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이게 다 뭐야. 햄버거, 삼각김밥에 도너츠?","JPN":"なんなの、これは？　ハンバーガーにおにぎり、ドーナツ？","ENG":"What's all this? Burgers, chips, and donuts?","TWN":"這都是什麼啊。漢堡，飯團和甜甜圈？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위는 이런 걸 도시락이라고 가져오는 거야?","JPN":"警部補はこんなものをお弁当だと言ってるの？","ENG":"You call this a lunchbox?","TWN":"警衛會把這種東西當便當帶嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 그렇게 감동하실 것까지야.","JPN":"はは、感動しちゃいました？","ENG":"Hah hah, there's no need to get that excited.","TWN":"哈哈，不用感謝我啦。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"감동 같은 소리하네!! 도시락이란 건 집에서 만들어 오는 거라고!","JPN":"感動してないわ！！　お弁当は家で作るものでしょ！","ENG":"Excited, my butt! You're supposed to make your own food for a lunchbox!","TWN":"我什麼時候感謝妳了！！而且便當是指在家做的料理啊！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여기엔 대놓고 편의점 스티커까지 붙어있잖아!","JPN":"ここに大きなコンビニシールも貼られているじゃない！","ENG":"You didn't even remove the price tag from this!","TWN":"這裡還貼著便利商店的貼紙耶！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 전 요리 같은 건 잘 못하는걸요.","JPN":"でも私、料理が下手なんです。","ENG":"But I can't cook.","TWN":"但我不太會做料理嘛。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님처럼 계란말이에 예쁜 문어 모양 소시지를 만들어 오는 건 무리라고요.","JPN":"警視様みたいに玉子焼きとか可愛いタコさんウインナーを作ってくるなんて、私には無理です。","ENG":"I can't make my omelet all pretty like yours. Or cut my sausages all fancy like that.","TWN":"不可能像警正一樣做出這麼漂亮的雞蛋捲，或者是章魚形狀的香腸啊。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럴 거면 번갈아 도시락을 싸오자는 소리는 왜 한 거야?","JPN":"だったら、交替でお弁当を作ろうとか言わないでよ！","ENG":"Then why did you even bother suggesting we should take turns bringing lunch?","TWN":"那妳為什麼還要提出輪流做便當的主意？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 경정님이 만들어 주신 도시락이 맛있어서 랄까?","JPN":"だって、警視様が作ってくれるお弁当は美味しいんですよ。","ENG":"Well, the lunch you bring is so good, you know?","TWN":"因為覺得妳做的便當太好吃了？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가 당신 요리사야?! 가정부야?!!","JPN":"私はあなた専属のシェフでもないし、家政婦でもない！","ENG":"I'm not your cook! Or your maid!","TWN":"我是妳的專屬廚師嗎？！還是保姆？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그렇게 도시락이 먹고 싶으면 편의점에서 사먹으시지!!","JPN":"そんなにお弁当が食べたかったら、コンビニで買って食べればいいじゃない！！","ENG":"Why don't you just buy your own lunch at the convenience store like this, huh?!","TWN":"那麼想吃便當就自己去便利商店買啊！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"에이, 그런 건 그 동안 질리도록 먹었다고요.","JPN":"いやぁ、コンビニ弁当はたくさん食べて飽きたんですよね。","ENG":"Oh, come on. I'm so sick and tired of that junk.","TWN":"哎呀，便利商店的東西都吃膩了嘛。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자취생활 10년만에 정기적으로 집밥을 얻어 먹을 수 있는 기회가 생겼는데 놓칠 순 없죠.","JPN":"10年ぶりに、やっと定期的に手作り弁当をいただくチャンスが巡ってきたんだから、見逃すわけにはいきませんよ。","ENG":"I finally have a chance to get homemade meals after 10 years of living on my own. I won't miss this chance.","TWN":"都過了10年的獨居生活了，我可不想錯過能定期吃到家常菜的機會啊。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"Ugh...","TWN":"哈啊……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 안 드실 거에요?","JPN":"それで、食べないんですか？","ENG":"So you're not going to dig in?","TWN":"所以妳不吃嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"입맛에 안 맞더라도 잠복수사를 할 때는 영양보충이 필수라고요.","JPN":"お口に合わなくても、張り込みの時は栄養補給が必須なんです。","ENG":"Even if you don't want to eat this, it's essential to get a hearty meal before a stakeout.","TWN":"就算不合味口也得吃喔，跟監時補充營養的食品可是不可或缺的呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"됐어. 이럴 줄 알고 내 도시락은 따로 싸왔으니까.","JPN":"いいよ、もう……こうなると思ってもう一個持ってきたから。","ENG":"Forget it. I knew this was going to happen so I brought my own lunch.","TWN":"算了。我就知道會這樣，所以另外準備了自己的便當。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정말이요? 오, 역시 우리 경정님! 저도 같이 먹어도 되죠?","JPN":"本当ですか？　おぉ、さすが警視様！　いただきます！","ENG":"Really? Ooh, I knew I could count on you! Can I have some of your food?","TWN":"真的嗎？喔，不愧是我們警正大人！我也可以一起吃吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알았어! 알았으니까 저리 좀 떨어져!! 이 생활능력 파탄자!!","JPN":"わかった！　わかったからあっち行って！！　この生活能力ゼロ！！","ENG":"Fine! Just give me some space! You're such a slob!","TWN":"知道了！知道了啦，所以離我遠一點！！別讓我說第二遍！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그나저나 오늘은 뭣 때문에 잠복근무를 하는 거야?","JPN":"ところで、今日は何のために張り込みなんてするの？","ENG":"Anyway, why are we going on a stakeout today?","TWN":"話說為什麼要選擇今天埋伏啊？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 제가 얘길 안 드렸던가요?","JPN":"あ、話してませんでした？","ENG":"Oh, didn't I tell you?","TWN":"啊，我沒和妳說過嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"요즘 고층건물에 불법 그래피티를 하는 카운터 범죄자가 나타났다고 하더라고요.","JPN":"最近高層ビルで、違法に落書きを描くカウンター犯罪者が現れたそうです。","ENG":"Recently some Counters have been drawing illegal graffiti on skyscrapers.","TWN":"聽說最近經常出現在高層建築上非法塗鴉的制裁者罪犯。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐야 그 바보는......?","JPN":"何なの、そのバカは……？","ENG":"What kind of an idiot would do that?","TWN":"吃飽了沒事幹嗎……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"대체 왜 카운터 능력을 그런 곳에 쓰는 건데?","JPN":"いったいどうしてカウンター能力をそんなところに使うの？","ENG":"Why waste Counter abilities on something like that?","TWN":"為什麼要把制裁者的能力用在那種地方啊？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 본인들 말로는 범죄가 아니라 예술적인 퍼포먼스라는데......","JPN":"はは、本人たちの話では、犯罪じゃなくアートパフォーマンスだそうですが……","ENG":"Hah hah, according to them, it's an artistic performance, not a crime.","TWN":"哈哈，他們本人的說辭是「這並非犯罪，而是一種藝術表現形式」……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"물론 건물주들은 그 의견에 동의하지 않는 것 같아요.","JPN":"もちろんビルオーナーたちは、その意見に同意していないようです。","ENG":"Of course, the building's owners don't seem to agree with that.","TWN":"當然，房東們似乎不接受這種說法。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 우리가 여기 숨어 있는 거고요.","JPN":"だから、私たちがここに隠れているわけです。","ENG":"And that's why we're hiding here right now.","TWN":"所以我們就只好埋伏在這裡了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하여간 세상은 넓고 바보들은 많다니까......","JPN":"まったく、世の中バカだらけね……","ENG":"I've got to say, there's all sorts of idiots in this world...","TWN":"在廣大的世界裡果然有很多笨蛋……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잠깐, 그런데 아까 <color=#ffd34c>본인들</color>이라고 하지 않았어?","JPN":"待って、さっき<color=#ffd34c>本人たち</color>って言ったわよね？","ENG":"Wait, did you just say <color=#ffd34c>them</color> though?","TWN":"等等，妳剛才說 <color=#ffd34c>他們</color>？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 용의자는 남매로 이루어진 2인조 카운터에요.","JPN":"はい。容疑者は2人組の兄妹のカウンターです。","ENG":"Yup. The suspects are a Counter duo. A brother and a sister.","TWN":"對，嫌疑人是由兄妹組成的制裁者雙人組。"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"남매......","JPN":"兄妹……","ENG":"Siblings, huh...","TWN":"兄妹……"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위, 혹시 그 녀석들 말고도 친 형제가 모두 카운터인 경우가 많을까?","JPN":"マエカワ警部補、もしかしてそいつら以外に兄弟や姉妹がみんなカウンターである場合は多い？","ENG":"Lieutenant Kang, do you think there are lots of other siblings who are both Counters out there?","TWN":"姜警衛，除了那兩個傢伙，一對姐妹兩人都是制裁者的情況常見嗎？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"예를 들어서...... 동생이 카운터로 각성을 하면 형이나 언니도 카운터가 된다던가?","JPN":"例えば……弟とか妹がカウンターに覚醒したら兄や姉もカウンターになるとか？","ENG":"For example... If the younger sibling becomes a Counter, the other brother or sister eventually becomes one, too.","TWN":"比如說……因為妹妹覺醒，導致姐姐也覺醒成為制裁者之類的？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"글쎄요. 그런 통계는 본 적이 없네요.","JPN":"わかりません。そのような統計は見たことないですね。","ENG":"Beats me. I've never seen any statistics on that.","TWN":"不知道耶，我沒有看過這種統計數字。"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 워치를 가진 사람이 카운터가 되는 거라고 하니까......","JPN":"だけど、ウォッチを持つ人がカウンターになるらしいから……","ENG":"Then again, I heard you become a Counter if you have the Watch...","TWN":"但我聽說過擁有能量環的人會成為制裁者……"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"형제가 비슷한 경로로 같은 워치를 구했다면 그럴 수도 있지 않을까요?","JPN":"兄弟が類似したルートで同じウォッチを手に入れたら、そんなこともありじゃないでしょうか？","ENG":"So maybe that could be possible if the siblings got the same Watch from similar sources.","TWN":"那麼也有可能兩人通過相似途徑找到同樣的能量環吧？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러고 보니 경정님은 어떻게 워치를 얻으셨어요? 혹시 길에서 주웠다던가?","JPN":"そういえば、警視様はどうやってウォッチを手に入れたんですか？　もしかして道端で拾いました？","ENG":"Speaking of which, how did you get your Watch? Did you find it on the street or something?","TWN":"這麼說來，警正是怎麼拿到能量環的？難道是在路上撿到的嗎？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리야? 길에 떨어진 물건을 왜 주워?!","JPN":"何バカなことを言ってるの！　道端に落ちているものを拾うわけないじゃない！！","ENG":"Don't be ridiculous! Why would I pick up something from the street?!","TWN":"妳在說什麼蠢話？為什麼要去撿掉在地上的東西？"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"전 이것저것 많이 줍는 편인데......","JPN":"私は結構いろいろ拾いますけど……","ENG":"I tend to find a lot of useful stuff on the street...","TWN":"我倒是經常撿東西……"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이건 아빠한테 선물 받은 거야!","JPN":"これは父からもらったプレゼントなの！","ENG":"This was a present from my dad!","TWN":"這是我父親給我的禮物！"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하여간 쓸데없는 데 신경 쓰지 말고 잠복 수사답게 감시나 잘 해!","JPN":"まったく、余計なことは気にしないで張り込みに集中しなさいよ！","ENG":"Stop distracting yourself and just focus on the stakeout!","TWN":"總之別想那些有的沒的，先把現在的任務放在第一位！"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 당장이라도 저 앞에 범죄자들이 나타날 수......","JPN":"今すぐにでも目の前に犯罪者たちが現れ……","ENG":"The suspects could appear any moment now—","TWN":"要是犯罪分子突然出現在我們面前……"},"stage":{"bg":"VEHICLE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하하! 시대를 앞서 태어난 초차원 예술가 드로잉 맨, 여기 등장!","JPN":"はは！　時代を先取りして生まれた超次元芸術家ドローイングマン、ここに登場！","ENG":"Hah hah! Here comes Drawing Man, the hyperdimensional artist ahead of his time!","TWN":"哈哈！跨時代的天才，超次元的藝術家，繪畫者男孩登場！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그의 여동생이자 주관을 초월한 객관적 평론가 스캡틱 걸, 같이 등장!","JPN":"彼の妹であり、主観を超えて客観性を持つ評論家スケプティックガール、同じく登場！","ENG":"And here comes his sister and the super objective critic, Skeptic Girl!","TWN":"他的妹妹，超越主觀的客觀評論家，懷疑論女孩也一同登場！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘은 이 빌딩이 나의 캔버스인가? 시대를 앞선 나의 예술! 잘 보여주도록 하지!","JPN":"今日はこのビルが私のキャンバスなのか！　時代を先取りする私の芸術！　しかと見せてあげるとしよう！","ENG":"Shall this building serve as my canvas today? Behold, my art that transcends beyond this era! I shall unfold it right here!","TWN":"我今天的畫布是這座大樓嗎？我超越時代的藝術！讓我把完美的作品展示給大家吧！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"와, 저렇게 동네방네 떠들썩하게 등장할 줄이야.","JPN":"わぁ、あんなに騒がしく登場するんだ。","ENG":"Wow, who knew they'd make such a grand entrance?","TWN":"哇，出場好華麗啊。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이래서야 잠복하고 있던 보람이 없는데요?","JPN":"こうなると、張り込みの意味がないですね。","ENG":"This sort of defeats the purpose of the stakeout, doesn't it?","TWN":"我們是不是白白埋伏在這裡了？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥, 저 뻔뻔한 꼬맹이들이......!","JPN":"ふん、図々しいやつらめ……！","ENG":"Hmpf, those shameless kids!","TWN":"哼，厚顏無恥的小鬼們……！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잡히면 아주 박살을 내버릴 줄 알아! 거기서!!","JPN":"捕まえたら容赦しないわ！　待ちなさい！！","ENG":"They'll be sorry when I get my hands on them! Stop right there!","TWN":"要是被我逮到，看我不把他們全砍了！看招！"},"stage":{"bg":"SKY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"겨, 경정님! 칼은 내려놓고 가셔야죠!","JPN":"け、警視様！　刀は下ろしてください！","ENG":"M-Major! Maybe you should leave your sword behind?!","TWN":"警、警正！先把刀放下再說！"},"stage":{"bg":"SKY","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};